class Solution {
    public int maxConsecutiveAnswers(String answerKey, int k) {
        int countT = countT(answerKey);
        int countF = countF(answerKey);
        int maxConsecutive = Math.min(countT, countF);
        if (k > 0) {
            maxConsecutive = Math.max(maxConsecutive, k);
            maxConsecutive = Math.min(maxConsecutive, countT - k + countF - k);
        }
        return maxConsecutive;
    }

    private int countT(String answerKey) {
        int count = 0;
        for (int i = 0; i < answerKey.length(); i++) {
            if (answerKey.charAt(i) == 'T') {
                count++;
            }
        }
        return count;
    }

    private int countF(String answerKey) {
        int count = 0;
        for (int i = 0; i < answerKey.length(); i++) {
            if (answerKey.charAt(i) == 'F') {
                count++;
            }
        }
        return count;
    }
}
